blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie nauczysz się <strong>zaimków względnych</strong> - słów łączących zdania i dających dodatkowe informacje.",
    "rules": [
        {
            "label": "KTO",
            "color": "emerald",
            "text": "<strong>Kto</strong> — dla osób (temat/dodatek):",
            "example": "Człowiek, który dzwonił, to mój szef."
        },
        {
            "label": "KTÓRY",
            "color": "blue",
            "text": "<strong>Który</strong> — w sprawach i sprawach zwierzęta:",
            "example": "Książka, którą przeczytałem była świetna."
        },
        {
            "label": "TO",
            "color": "amber",
            "text": "<strong>To</strong> jest uniwersalne (ludzie/rzeczy):",
            "example": "Samochód, który kupił, jest nowy."
        }
    ]
}

{
    "title": "1. Pięć podstawowych zaimków względnych (rzeczy)",
    "intro": "Кожен відносний займенник має своє використання:",
    "items": [
        {
            "label": "WHO",
            "title": "Хто (люди)",
            "subtitle": "підмет або додаток — The woman who lives here..."
        },
        {
            "label": "WHICH",
            "title": "Який (речі)",
            "subtitle": "rzeczy i zwierzęta — Czerwony samochód..."
        },
        {
            "label": "TO",
            "title": "Co/które (uniwersalne)",
            "subtitle": "ludzie lub rzeczy — Książka, którą ja przeczytaj..."
        },
        {
            "label": "KOGO",
            "title": "Czyj (należący do)",
            "subtitle": "wykazuje posiadanie — Mężczyzna, któremu skradziono samochód..."
        },
        {
            "label": "KOGO",
            "title": "Kto (formalnie)",
            "subtitle": "załącznik (język formalny) — Osoba, którą poznałem..."
        }
    ]
}

{
    "title": "2. WHO jest dla ludzi",
    "sections": [
        {
            "label": "Kto jako temat",
            "color": "emerald",
            "description": "<strong>Kto</strong> jest używany w odniesieniu do ludzi. Może być <strong>tematem</strong> w zdaniu względnym.",
            "examples": [
                {
                    "en": "Mężczyzna, który zadzwonił, to mój szef.",
                    "ua": "Mężczyzna, który zadzwonił, to mój szef."
                },
                {
                    "en": "Kobieta, która tu mieszka, jest lekarzem.",
                    "ua": "Kobieta, która tu mieszka, jest lekarzem lekarz."
                },
                {
                    "en": "Ludzie, którzy regularnie ćwiczą, są zdrowi. <strong>dodatek</strong> (nieformalnie zamiast kogo).",
                    "ua": "Люди, які регулярно займаються спортом, здоровіші."
                },
                {
                    "en": "The teacher who taught me was excellent.",
                    "ua": "Вчитель, який мене навчав, був чудовим."
                }
            ]
        },
        {
            "label": "Who як додаток",
            "color": "sky",
            "description": "<strong>Who</strong> може бути <strong>додатком</strong> (неформально замість whom).",
            "examples": [
                {
                    "en": "Mężczyzna, którego spotkałem, był przyjacielski.",
                    "ua": "Mężczyzna, którego spotkałem, był przyjacielski."
                },
                {
                    "en": "Osoba, do której dzwoniłeś, jest tutaj.",
                    "ua": "Osoba, do której dzwoniłeś, to tutaj."
                },
                {
                    "en": "Kobieta, którą widzieliśmy wczoraj, była moją sąsiadką. Dla zwierząt i rzeczy – które lub tamto.",
                    "ua": "Жінка, яку ми бачили вчора, — моя сусідка."
                }
            ],
            "note": "📌 Who замість whom — неформально, але дуже поширено!"
        },
        {
            "label": "Who НЕ для тварин/речей",
            "color": "purple",
            "description": "<strong>Who</strong> тільки для людей! Для тварин і речей — which або that.",
            "examples": [
                {
                    "en": "Pies, który szczeka... (✗)",
                    "ua": "BŁĄD"
                },
                {
                    "en": "Pies, który/który szczeka... (✓)",
                    "ua": "Pies, który szczeka..."
                }
            ]
        }
    ]
}

{
    "title": "3. KTÓRY dotyczy rzeczy i zwierząt",
    "sections": [
        {
            "label": "Który dotyczy rzeczy",
            "color": "blue",
            "description": "<strong>Którą</strong> stosuje się do rzeczy i zwierząt (nie do ludzi).",
            "examples": [
                {
                    "en": "Książka, którą przeczytałem, była świetna.",
                    "ua": "Książka, którą przeczytałem, była świetna."
                },
                {
                    "en": "Czerwony samochód jest mój.",
                    "ua": "Samochód, który jest czerwony — mój."
                },
                {
                    "en": "Dom, który kupiliśmy jest stary.",
                    "ua": "Dom, który kupiliśmy jest stary."
                },
                {
                    "en": "Telefon, który chcę, kosztuje dużo.",
                    "ua": "Telefon, który chcę, kosztuje dużo."
                }
            ]
        },
        {
            "label": "Który dla zwierzęta",
            "color": "sky",
            "description": "To samo dotyczy zwierząt.",
            "examples": [
                {
                    "en": "Pies, który mieszka obok, jest przyjazny.",
                    "ua": "Pies, który mieszka obok, jest przyjazny."
                },
                {
                    "en": "Kot, którego widziałem, był czarny.",
                    "ua": "Kot, którego widziałem, był czarny czarny."
                }
            ]
        },
        {
            "label": "Co za całe zdanie",
            "color": "purple",
            "description": "<strong>Co</strong> może odnosić się do całego poprzedniego wyrażenia (z przecinkiem!).",
            "examples": [
                {
                    "en": "Zdał egzamin, co wszystkich zaskoczyło.",
                    "ua": "Zdał egzamin, co zaskoczyło wszyscy."
                },
                {
                    "en": "Przyjechała późno, co mnie złości.",
                    "ua": "Przyjechała późno, co mnie zdenerwowało."
                }
            ],
            "note": "📌 , co = nawiązanie do całej sytuacji."
        }
    ]
}

{
    "title": "4. TO jest zaimek uniwersalny",
    "sections": [
        {
            "label": "To dla ludzi i rzeczy",
            "color": "amber",
            "description": "<strong>To</strong> jest uniwersalne! Można użyć zamiast kto lub który (ale nie zawsze!).",
            "examples": [
                {
                    "en": "Człowiek, który zadzwonił... = Człowiek, który zadzwonił...",
                    "ua": "Człowiek, który zadzwonił..."
                },
                {
                    "en": "Książka, którą przeczytałem... = Książka, którą przeczytałem...",
                    "ua": "Książka, którą czytałem..."
                },
                {
                    "en": "Samochód, który kupił, jest nowy.",
                    "ua": "Samochód, który kupił, jest nowy."
                }
            ]
        },
        {
            "label": "Kiedy MUSISZ tego użyć",
            "color": "emerald",
            "description": "Po <strong>superlatywach, wszystko, wszystko, tylko, pierwszy/ostatni</strong> lepiej to wykorzystać.",
            "examples": [
                {
                    "en": "To najlepszy film, jaki kiedykolwiek widziałem.",
                    "ua": "To najlepszy film, jaki kiedykolwiek widziałem."
                },
                {
                    "en": "Wszystko, co powiedział, było prawdą.",
                    "ua": "Wszystko, co powiedział, było prawdą prawda."
                },
                {
                    "en": "Ona jest jedyną osobą, która może pomóc.",
                    "ua": "Ona jest jedyną osobą, która może pomóc."
                },
                {
                    "en": "Jestem tu po raz pierwszy.",
                    "ua": "Jestem tu po raz pierwszy tutaj."
                }
            ],
            "note": "📌najlepiej, wszyscy, wszyscy, tylko, najpierw → użyj tego!"
        },
        {
            "label": "Kiedy NIE używać tego",
            "color": "rose",
            "description": "Tego <strong>NIE</strong> można używać z przecinkiem (zdania nieokreślające).",
            "examples": [
                {
                    "en": "Mój brat, który mieszka w Kijowie, jest lekarzem. (✓)",
                    "ua": "Mój brat, który mieszka w Kijowie, jest lekarzem."
                },
                {
                    "en": "Mój brat, który mieszka w Kijowie, jest lekarzem. (✗)",
                    "ua": "BŁĄD z tym po przecinku!"
                }
            ],
            "note": "📌 Z przecinkiem - tylko kto/który, NIE to!"
        }
    ]
}

{
    "title": "5. KOGO – którego (przynależność)",
    "sections": [
        {
            "label": "Kto pokazuje własność",
            "color": "purple",
            "description": "<strong>Czyj</strong> (czyj) pokazuje przynależność. Używane do oznaczania osób i rzeczy.",
            "examples": [
                {
                    "en": "Mężczyzna, którego samochód został skradziony, wezwał policję.",
                    "ua": "Mężczyzna, którego samochód został skradziony, wezwał policję."
                },
                {
                    "en": "Mieszka tu kobieta, której córka jest lekarzem.",
                    "ua": "Mieszka tu kobieta, której córka jest lekarzem."
                },
                {
                    "en": "Znam osobę, której brat jest sławny.",
                    "ua": "Znam osobę, której brat jest sławny."
                }
            ]
        },
        {
            "label": "Czyj + rzeczownik",
            "color": "blue",
            "description": "<strong>którego</strong> zawsze następuje po <strong>rzeczownik. czyja siostra).",
            "examples": [
                {
                    "en": "The boy whose bike was stolen... (✓)",
                    "ua": "Хлопець, чий велосипед вкрали..."
                },
                {
                    "en": "The boy whose was stolen... (✗)",
                    "ua": "ПОМИЛКА — потрібен іменник!"
                }
            ],
            "note": "📌 Whose завжди + noun (чий велосипед, чия сестра)."
        },
        {
            "label": "Nie myl czyj z kim",
            "color": "amber",
            "description": "<strong>Czyj</strong> (chis) ≠ <strong>kto</strong> (kto jest/ma).",
            "examples": [
                {
                    "en": "Człowiek, którego samochód... (zaborczy)",
                    "ua": " samochód..."
                },
                {
                    "en": "Mężczyzna, który dzwoni... (kto jest)",
                    "ua": "Człowiek, który dzwoni..."
                }
            ],
            "note": "📌 Czyj = czyj. Kto jest = kto jest."
        }
    ]
}

{
    "title": "6. KTO to język formalny",
    "sections": [
        {
            "label": "Kto jako dodatek (formalnie)",
            "color": "sky",
            "description": "<strong>Whom</strong> to formalny wariant who jako dodatek. W mowie potocznej zwykle używa się słowa „kto”.",
            "examples": [
                {
                    "en": "Osoba, którą poznałem, była miła. (formalny)",
                    "ua": "Osoba, którą poznałem, była miła."
                },
                {
                    "en": "Osoba, którą poznałem, była miła. (nieformalne)",
                    "ua": "To samo, ale wersja mówiona."
                }
            ]
        },
        {
            "label": "Kto po przyimkach",
            "color": "purple",
            "description": "Po przyimkach (z, do, dla) <strong>kogo</strong> jest formalnie używane.",
            "examples": [
                {
                    "en": "Osoba, z którą rozmawiałem... (formalne)",
                    "ua": "Osoba, z którą rozmawiałem..."
                },
                {
                    "en": "Osoba, z którą rozmawiałem... (nieformalne)",
                    "ua": "To samo, potocznie."
                }
            ],
            "note": "📌 Kogo prawie nigdy nie używa się w mowie potocznej."
        }
    ]
}

{
    "title": "7. Zdania definiujące a niedefiniujące",
    "sections": [
        {
            "label": "Definiowanie - bez przecinka",
            "color": "emerald",
            "description": "<strong>Zdania definiujące</strong> - ważne informacje (bez niego zdanie jest niejasne). Bez komunikatora!",
            "examples": [
                {
                    "en": "Mężczyzna, który dzwonił, to mój szef.",
                    "ua": "Mężczyzna, który dzwonił, to mój szef. (która dokładnie?)"
                },
                {
                    "en": "Książka, którą przeczytałem, była świetna.",
                    "ua": "Książka, którą przeczytałem, była świetna. (jaka książka?)"
                }
            ],
            "note": "📌 Definicja = ważna informacja. Bez kom. Możesz to zrobić."
        },
        {
            "label": "Nieokreślony - z przecinkami",
            "color": "blue",
            "description": "<strong>Zdania nieokreślone</strong> - dodatkowe informacje (można usunąć). Przecinkami!",
            "examples": [
                {
                    "en": "Mój brat, który mieszka w Kijowie, jest lekarzem.",
                    "ua": "Mój brat, który mieszka w Kijowie, jest lekarzem."
                },
                {
                    "en": "Londyn, który jest stolicą, jest duży.",
                    "ua": "Londyn, który jest stolicą, jest duży duży."
                }
            ],
            "note": "📌 Nieokreślony = dodatkowe informacje. Z przecinkami. Tylko kto/który!"
        },
        {
            "label": "Kluczowe różnice",
            "color": "amber",
            "description": "Definiowanie (bez przecinków) jest wymaganą informacją. Nieokreślone (z przecinkami) jest opcjonalne.",
            "examples": [
                {
                    "en": "Uczniowie, którzy ciężko pracują, zdają egzaminy. (nie wszyscy, tylko ci, którzy pracują)",
                    "ua": "definiowanie"
                },
                {
                    "en": "Moi uczniowie, którzy ciężko pracują, zdają egzaminy. (wszyscy moi uczniowie)",
                    "ua": "nieokreślający"
                }
            ],
            "note": "Przecinki zmieniają znaczenie zdania!"
        }
    ]
}

{
    "title": "8. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "To po przecinku (nieokreślony).",
            "wrong": "My brother, that lives in Kyiv, is a doctor.",
            "right": "✅ <span class="font-mono">My brother, who lives in Kyiv, is a doctor.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Who для речей або тварин.",
            "wrong": "The book who I read... / The dog who barks...",
            "right": "✅ <span class="font-mono">The book that/which I read... / The dog that/which barks...</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Плутанина whose і who's.",
            "wrong": "The man who's car was stolen... (who is car?)",
            "right": " ✅ <span class="font-mono">Człowiek, którego samochód został skradziony...</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Zbędny zaimek po zaimku względnym.",
            "wrong": "Człowiek, do którego zadzwonił, to mój szef.",
            "right": " ✅ <span class="font-mono">Mężczyzna, który dzwonił, jest moim szefem.</span>"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy zaimek",
    "select_intro": "Wpisz w puste miejsca właściwy zaimek względny.",
    "selects": [
        {
            "label": "Mężczyzna, do którego zadzwonił ___, jest moim szefem. (kto / który)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "Książka ___, którą przeczytałam, była świetna. (kto / który)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "Kobiecie ___ skradziono samochód... (czyj/kto)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "To najlepszy film ___ jaki widziałem. (to / które)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "Mój brat ___ mieszka w Kijowie... (to / kto)",
            "prompt": "Który zaimek?"
        }
    ],
    "options": [
        "kto",
        "który",
        "że",
        "czyj",
        "który"
    ],
    "input_title": "Ćwiczenie 2. Wypełnij puste miejsca",
    "input_intro": "Wpisz właściwy zaimek względny.",
    "inputs": [
        {
            "before": "Kobieta ___, do której dzwoniono, jest lekarzem. (kobieta, która)",
            "after": " →"
        },
        {
            "before": "Samochód ___, który kupiłem, jest nowy. (samochód)",
            "after": "→"
        },
        {
            "before": "Człowiek ___ pies jest duży... (człowiek, którego pies)",
            "after": " →[[CODX_SEG_23]]]Wszystko ___ powiedział było prawdą. (wszystko to)"
        },
        {
            "before": "Everything ___ he said was true. (усе, що)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd z zaimkami względnymi.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Książka, którą I przeczytaj...",
            "example_target": "Książka, którą/którą przeczytałem..."
        },
        {
            "original": "1. Mój brat mieszka w Kijowie jest lekarzem.",
            "placeholder": "Popraw błąd"
        },
        {
            "original": "2. Pies, który szczeka, jest mój.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Mężczyzna, któremu skradziono samochód...",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne strony z kategorii Zaimki i słowa orientacyjne",
    "items": [
        {
            "label": "Zaimki - Zaimki (przegląd)",
            "current": false
        },
        {
            "label": "Zaimki osobowe i przedmiotowe",
