        },
        {
            "label": "Przymiotniki dzierżawcze a zaimki",
            "current": false
        },
        {
            "label": "Zaimki nieokreślone",
            "current": false
        },
        {
            "label": "Zaimki zwrotne",
            "current": false
        },
        {
            "label": "Zaimki względne — kto, który, to, którego (prąd)",
            "current": true
        }
    ]
